function nowIso(){return new Date().toISOString();}
function monthStamp(d){const y=d.getUTCFullYear(); const m=String(d.getUTCMonth()+1).padStart(2,"0"); return `${y}-${m}`;}
function isLastDayOfMonth(d){const next=new Date(Date.UTC(d.getUTCFullYear(),d.getUTCMonth(),d.getUTCDate()+1)); return next.getUTCMonth()!==d.getUTCMonth();}

async function getAccessToken(cfg){
  const body=new URLSearchParams({
    client_id: cfg.oauthClientId,
    client_secret: cfg.oauthClientSecret,
    refresh_token: cfg.oauthRefreshToken,
    grant_type: "refresh_token"
  });
  const resp=await fetch("https://oauth2.googleapis.com/token",{method:"POST",headers:{"Content-Type":"application/x-www-form-urlencoded"},body});
  if(!resp.ok){throw new Error(`token_error_${resp.status}: ${await resp.text()}`);}
  const data=await resp.json();
  return data.access_token;
}

async function gapi({method,url,token,body}){
  const resp=await fetch(url,{method,headers:{Authorization:`Bearer ${token}`,"Content-Type":"application/json"},body:body?JSON.stringify(body):undefined});
  const txt=await resp.text();
  let data={}; try{data=txt?JSON.parse(txt):{};}catch(_){data={raw:txt};}
  if(!resp.ok){throw new Error(`google_api_${resp.status}: ${txt}`);}
  return data;
}

async function main(){
  const cfg={
    templateFileId:String(input.templateFileId||""),
    parentFolderId:String(input.parentFolderId||""),
    controlSpreadsheetId:String(input.controlSpreadsheetId||""),
    managerEmail:String(input.managerEmail||""),
    oauthClientId:String(input.oauthClientId||""),
    oauthClientSecret:String(input.oauthClientSecret||""),
    oauthRefreshToken:String(input.oauthRefreshToken||""),
  };
  const force=(input.forceRun===true)||(String(input.forceRun||"" ).toLowerCase()==="true");
  if(!cfg.templateFileId||!cfg.parentFolderId||!cfg.controlSpreadsheetId||!cfg.managerEmail||!cfg.oauthClientId||!cfg.oauthClientSecret||!cfg.oauthRefreshToken){
    throw new Error("missing_required_input");
  }

  const today=new Date();
  if(!force && !isLastDayOfMonth(today)){
    return {ran:false,reason:"not_last_day",date:today.toISOString()};
  }

  const token=await getAccessToken(cfg);
  const month=monthStamp(today);

  const trackerReadUrl=`https://sheets.googleapis.com/v4/spreadsheets/${cfg.controlSpreadsheetId}/values/${encodeURIComponent("tracker!A2:G")}`;
  const trackerData=await gapi({method:"GET",url:trackerReadUrl,token});
  const trackerRows=Array.isArray(trackerData.values)?trackerData.values:[];
  const existingKeys=new Set();
  for(const row of trackerRows){
    const m=String((row&&row[0])||"").trim();
    const e=String((row&&row[1])||"").trim().toLowerCase();
    if(m && e) existingKeys.add(`${m}|${e}`);
  }

  const leadUrl=`https://sheets.googleapis.com/v4/spreadsheets/${cfg.controlSpreadsheetId}/values/${encodeURIComponent("lead_registry!A2:B")}`;
  const leadData=await gapi({method:"GET",url:leadUrl,token});
  const rows=Array.isArray(leadData.values)?leadData.values:[];

  const created=[];
  const skipped=[];
  for(const row of rows){
    const leadName=String((row&&row[0])||"").trim();
    const leadEmail=String((row&&row[1])||"").trim();
    if(!leadName||!leadEmail) continue;

    const key=`${month}|${leadEmail.toLowerCase()}`;
    if(existingKeys.has(key)){
      skipped.push({leadEmail, reason:"already_provisioned_for_month"});
      continue;
    }

    const copyUrl=`https://www.googleapis.com/drive/v3/files/${cfg.templateFileId}/copy?supportsAllDrives=true&fields=id,name,webViewLink`;
    const copied=await gapi({method:"POST",url:copyUrl,token,body:{name:`Timesheet ${month} - ${leadName}`,parents:[cfg.parentFolderId]}});
    const fileId=String(copied.id||"");
    const sheetUrl=String(copied.webViewLink||"");

    const leadPermUrl=`https://www.googleapis.com/drive/v3/files/${fileId}/permissions?supportsAllDrives=true&sendNotificationEmail=true&emailMessage=${encodeURIComponent("Please fill your timesheet.")}`;
    await gapi({method:"POST",url:leadPermUrl,token,body:{type:"user",role:"writer",emailAddress:leadEmail}});

    const mgrPermUrl=`https://www.googleapis.com/drive/v3/files/${fileId}/permissions?supportsAllDrives=true&sendNotificationEmail=false`;
    await gapi({method:"POST",url:mgrPermUrl,token,body:{type:"user",role:"writer",emailAddress:cfg.managerEmail}});

    const appendUrl=`https://sheets.googleapis.com/v4/spreadsheets/${cfg.controlSpreadsheetId}/values/${encodeURIComponent("tracker!A2:G")}:append?valueInputOption=USER_ENTERED&insertDataOption=INSERT_ROWS`;
    await gapi({method:"POST",url:appendUrl,token,body:{values:[[month,leadEmail,leadName,fileId,sheetUrl,"sent",nowIso()]]}});

    created.push({leadEmail,leadName,fileId,sheetUrl});
    existingKeys.add(key);
  }

  return {ran:true,month,createdCount:created.length,skippedCount:skipped.length,created,skipped};
}

return await main();
